		cudaFree(d_params);
		cudaFree(d_com);
		free(err);
		free(scale);
		free(yy);
		free(com);
		return 0;
	}

	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
		last_interval = 1.0f;
	}

	for(k=1; k<=xmax; k++) {

		x[k] = (fp)(k-1);
		h = h_init;
		scale_fina = 1.0f;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(x[k],
			                      h,
			                      y[k-1],
			                      y[k],
			                      err,
			                      params,
			                      com,
			                      d_initvalu,
			                      d_finavalu,
			                      d_params,
			                      d_com);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0.0f){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0f){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabsf(y[k-1][i]);
				}
				scale[i] = 0.8f * powf( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i] < scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9f) {
				h = 0.9f;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5f * h > (fp)xmax ){
				h = 0.5f * h;
			}
		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			cudaFree(d_initvalu);
			cudaFree(d_finavalu);
			cudaFree(d_params);
			cudaFree(d_com);
			free(err);
			free(scale);
			free(yy);
			free(com);
			return -1;
		}
	}

	cudaFree(d_initvalu);
	cudaFree(d_finavalu);
	cudaFree(d_params);
	cudaFree(d_com);

	free(err);
	free(scale);
	free(yy);
	free(com);

	(void)last_interval;
	(void)mode;

	return 0;
}

int main(int argc, char *argv []){

	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;

	time0 = get_time();

	long long memory;
	int i,j;
	int status;
	int mode;

	long workload;
	long xmin;
	long xmax;
	fp h;
	fp tolerance;

	fp*** y;
	fp** x;
	fp** params;

	int threads;

	if(argc!=5){
		printf("ERROR: %d is the incorrect number of arguments, the number of arguments must be 4\n", argc-1);
		return 0;
	}
	else{

		xmax = atoi(argv[1]);
		if(xmax<0){
			printf("ERROR: %d is the incorrect end of simulation interval, use numbers > 0\n", (int)xmax);
			return 0;
		}

		workload = atoi(argv[2]);
		if(workload<0){
			printf("ERROR: %d is the incorrect number of instances of simulation, use numbers > 0\n", (int)workload);
			return 0;
		}

		mode = 0;
		mode = atoi(argv[3]);
		if(mode != 0 && mode != 1){
			printf("ERROR: %d is the incorrect mode, it should be omitted or equal to 0 or 1\n", mode);
			return 0;
		}

		threads = atoi(argv[4]);
		if(threads<0){
			printf("ERROR: %d is the incorrect number of threads, use numbers > 0\n", threads);
			return 0;
		}
	}

	time1 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4LL;
	if(memory>1000000000LL){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y = (fp ***) malloc(workload* sizeof(fp **));
	for(i=0; i<workload; i++){
		y[i] = (fp**)malloc((1+xmax)*sizeof(fp*));
		for(j=0; j<(1+xmax); j++){
			y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp));
		}
	}

	x = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		x[i]= (fp *)malloc((1+xmax) *sizeof(fp));
	}

	params = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		params[i]= (fp *)malloc(PARAMETERS * sizeof(fp));
	}

	time2 = get_time();

	for(i=0; i<workload; i++){
		read((char*)"../../data/myocyte/y.txt",
		     y[i][0],
		     91,
		     1,
		     0);
	}

	for(i=0; i<workload; i++){
		read((char*)"../../data/myocyte/params.txt",
		     params[i],
		     16,
		     1,
		     0);
	}

	time3 = get_time();

	if(mode == 0){
		for(i=0; i<workload; i++){
			status = solver(y[i],
			                x[i],
			                xmax,
			                params[i],
			                mode);
			(void)status;
		}
	}
	else{
		for(i=0; i<workload; i++){
			status = solver(y[i],
			                x[i],
			                xmax,
			                params[i],
			                mode);
			(void)status;
		}
	}

	time4 = get_time();

	for (i= 0; i< workload; i++){
		for (j= 0; j< (1+xmax); j++){
			free(y[i][j]);
		}
		free(y[i]);
	}
	free(y);

	for (i= 0; i< workload; i++){
		free(x[i]);
	}
	free(x);

	for (i= 0; i< workload; i++){
		free(params[i]);
	}
	free(params);

	time5= get_time();

	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES, READ COMMAND LINE ARGUMENTS\n", 	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE MEMORY\n", 									(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES\n", 								(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : RUN COMPUTATION\n", 									(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n", 										(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time5-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", 																(float) (time5-time0) / 1000000);

	(void)xmin;
	(void)h;
	(void)tolerance;
	(void)threads;

	return 0;
}
